
import { collection, getDocs, query, where, doc, getDoc, limit, writeBatch, setDoc, serverTimestamp, deleteField } from "https://www.gstatic.com/firebasejs/10.12.5/firebase-firestore.js";
import { onAuthStateChanged } from "https://www.gstatic.com/firebasejs/10.12.5/firebase-auth.js";
let F=window.ExploraFirebase||{},db=F.db||null,auth=F.auth||null,storage=F.storage||null;const $=id=>document.getElementById(id);
async function ensureDebtFirebase(timeoutMs=12000){const started=Date.now();while(Date.now()-started<timeoutMs){F=window.ExploraFirebase||F||{};db=F.db||db;auth=F.auth||auth;storage=F.storage||storage;if(db&&auth)return{db,auth,storage};await new Promise(resolve=>setTimeout(resolve,50));}throw makeDebtError("INITIALIZING_ADMIN_DEBT","FIREBASE_NOT_READY","Firebase todavía no está disponible para Pendientes.");}
const state={reason:"",installments:1,receiptFile:null,busy:false,saving:false,uploading:false,opened:false,drivers:new Map(),vehicles:new Map(),debts:new Map(),selectedVehicle:null,editingDebtId:"",diagnostic:null};
let debtSaveInProgress=false;
const ADMIN_ROLES=new Set(["admin","administrador","owner","superadmin"]);
const esc=value=>String(value??"").replace(/[&<>"']/g,char=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"}[char]));
const parseAmount=value=>window.parseCurrencyInput?.(value)||0;
const formatAmount=value=>window.formatCurrencyInput?.(value)||"";
const money=value=>new Intl.NumberFormat("es-AR",{style:"currency",currency:"ARS",maximumFractionDigits:0}).format(Number(value)||0).replace(/\s/g,"");
const normalizeRole=value=>String(value||"").trim().toLowerCase();
const formatBytes=value=>{const bytes=Number(value||0);if(!(bytes>0))return"—";if(bytes<1024)return`${bytes} B`;if(bytes<1024*1024)return`${Math.round(bytes/1024)} KB`;return`${(bytes/(1024*1024)).toFixed(2)} MB`;};
const storageBucket=()=>String(storage?.app?.options?.storageBucket||F.app?.options?.storageBucket||"").replace(/^gs:\/\//,"")||"—";
const DEBT_REASON_LABELS={fine:"Multa",crash:"Choque",personal_loan:"Préstamo",advance:"Adelanto"};
const DEBT_REASON_OPTIONS=Object.keys(DEBT_REASON_LABELS);
function debtReasonLabel(value){return DEBT_REASON_LABELS[clean(value)]||"Pendiente";}
function makeDebtError(stage,internalCode,message,cause=null,detail={}){const error=new Error(message||internalCode);error.code=internalCode;error.internalCode=internalCode;error.debtStage=stage;error.userMessage=message||internalCode;error.debtDetail=detail||{};if(cause){error.cause=cause;error.firebaseCode=String(cause.code||"");error.firebaseMessage=String(cause.message||cause||"");}return error;}
function isPermissionDenied(error){const code=String(error?.code||error?.message||"").toLowerCase();return code.includes("permission-denied")||code.includes("unauthorized");}
async function waitForDebtAuthReady(timeoutMs=8000){
  if(!auth)throw makeDebtError("VALIDATING_ADMIN_SESSION","AUTH_USER_MISSING","Firebase Authentication no está inicializado.");
  if(auth.currentUser?.uid)return auth.currentUser;
  return new Promise((resolve,reject)=>{let settled=false;let unsubscribe=null;const finish=(callback,value)=>{if(settled)return;settled=true;clearTimeout(timer);try{unsubscribe?.();}catch(_){}callback(value);};const timer=setTimeout(()=>finish(reject,makeDebtError("VALIDATING_ADMIN_SESSION","AUTH_USER_MISSING","No hay usuario autenticado en Firebase Auth. Cerrá sesión e ingresá nuevamente.")),timeoutMs);unsubscribe=onAuthStateChanged(auth,user=>{if(user?.uid)finish(resolve,user);});});
}
function roleInfo(profile={}){for(const field of ["role","rol","tipoUsuario","tipo","userRole"]){const raw=profile?.[field];if(String(raw??"").trim())return{field,value:String(raw).trim(),normalized:normalizeRole(raw)};}return{field:"",value:"",normalized:""};}
async function readDebtAdminProfile(user){
  if(!db)throw makeDebtError("ADMIN_ROLE_CHECK","FIRESTORE_ROLE_READ_DENIED","Firestore no está inicializado.");
  const session=window.ExploraSession||{};
  const username=String(user.email||"").trim().toLowerCase().split("@")[0]||"";
  const email=String(user.email||"").trim().toLowerCase();
  const candidates=[];const seen=new Set();
  const add=(collectionName,id,source)=>{const cleanCollection=String(collectionName||"").trim(),cleanId=String(id||"").trim();if(!cleanCollection||!cleanId)return;const key=`${cleanCollection}/${cleanId}`;if(seen.has(key))return;seen.add(key);candidates.push({collectionName:cleanCollection,id:cleanId,source});};
  add(session.profileCollection||session.profileRef?.parent?.id,session.profileDocumentId||session.driverId,"explora_session");
  add("choferes",user.uid,"uid");add("choferes",username,"username");
  let denied=null;
  for(const candidate of candidates){try{const ref=doc(db,candidate.collectionName,candidate.id),snap=await getDoc(ref);if(snap.exists())return{exists:true,id:snap.id,collectionName:candidate.collectionName,path:`${candidate.collectionName}/${snap.id}`,data:snap.data()||{},source:candidate.source};}catch(error){if(isPermissionDenied(error))denied=error;}}
  const querySpecs=[["uid",user.uid],["authUid",user.uid],["firebaseUid",user.uid],["email",email],["correo",email],["usuario",username],["username",username]].filter(([,value])=>Boolean(value));
  for(const [field,value] of querySpecs){try{const snap=await getDocs(query(collection(db,"choferes"),where(field,"==",value),limit(2)));if(!snap.empty){const item=snap.docs[0];return{exists:true,id:item.id,collectionName:"choferes",path:`choferes/${item.id}`,data:item.data()||{},source:`query_${field}`};}}catch(error){if(isPermissionDenied(error))denied=error;}}
  if(denied)throw makeDebtError("ADMIN_ROLE_CHECK","FIRESTORE_ROLE_READ_DENIED","Firestore no permitió leer el rol del usuario autenticado.",denied,{document:"choferes"});
  throw makeDebtError("ADMIN_ROLE_CHECK","USER_PROFILE_NOT_FOUND","No se encontró el perfil del usuario para validar permisos.",null,{document:"choferes"});
}
async function validateDebtAdminSession(){
  const user=await waitForDebtAuthReady(8000);
  if(!user?.uid)throw makeDebtError("VALIDATING_ADMIN_SESSION","AUTH_USER_MISSING","No hay usuario autenticado en Firebase Auth. Cerrá sesión e ingresá nuevamente.");
  const found=await readDebtAdminProfile(user);
  if(!found?.exists)throw makeDebtError("ADMIN_ROLE_CHECK","USER_PROFILE_NOT_FOUND","No existe documento de usuario para validar el rol.",null,{uid:user.uid});
  const info=roleInfo(found.data);
  if(!info.normalized)throw makeDebtError("ADMIN_ROLE_CHECK","USER_ROLE_MISSING","El documento del usuario no tiene campo de rol.",null,{profilePath:found.path,profileExists:true,roleField:"",roleValue:""});
  const isAdmin=ADMIN_ROLES.has(info.normalized);
  if(!isAdmin)throw makeDebtError("ADMIN_ROLE_CHECK","ADMIN_ROLE_REQUIRED","El usuario autenticado no tiene permisos de administrador para registrar deudas.",null,{profilePath:found.path,profileExists:true,roleField:info.field,roleValue:info.value,detectedRole:info.normalized,isAdmin:false});
  const appSession=window.ExploraSession||{};appSession.authUser=user;appSession.profile=found.data;appSession.profileDocumentId=found.id;appSession.profileCollection=found.collectionName;appSession.profileRef=doc(db,found.collectionName,found.id);appSession.role=info.normalized;appSession.initialized=true;
  return{user,uid:user.uid,email:user.email||"",role:info.normalized,profile:found.data,profileDocumentId:found.id,profileCollection:found.collectionName,profilePath:found.path,profileExists:true,roleField:info.field,roleValue:info.value,isAdmin:true};
}
window.ExploraValidateDebtAdminSession=validateDebtAdminSession;
async function activeDrivers(){const snapshot=await getDocs(query(collection(db,"choferes"),where("activo","==",true)));const rows=snapshot.docs.map(item=>({id:item.id,...item.data()})).filter(profile=>!ADMIN_ROLES.has(normalizeRole(profile.role||profile.rol||"")));state.drivers=new Map(rows.map(profile=>[String(profile.uid||profile.authUid||profile.id),profile]));return rows;}
async function activeVehicles(){const snapshot=await getDocs(collection(db,"vehiculos"));const rows=snapshot.docs.map(item=>({id:item.id,...item.data()}));state.vehicles=new Map(rows.map(vehicle=>[vehicle.id,vehicle]));return rows;}
async function activeDebts(){const snapshot=await getDocs(collection(db,"deudas_choferes"));const rows=snapshot.docs.map(item=>({id:item.id,...item.data()})).sort((a,b)=>String(b.incidentDate||b.createdAt?.seconds||"").localeCompare(String(a.incidentDate||a.createdAt?.seconds||"")));state.debts=new Map(rows.map(row=>[row.id,row]));return rows;}
function debtStatusLabel(row={}){const status=clean(row.status||row.debtStatus).toLowerCase(),remaining=Math.max(0,Number(row.remainingAmount??row.saldoPendiente??row.totalAmount??row.amount??0));if(status==="paid"||remaining<=0)return"🟢 Pagado";if(status==="installment")return"🟡 En cuotas";if(status==="cancelled"||status==="canceled")return"⚪ Cancelado";return"🔴 Pendiente";}
function debtAdminListMarkup(rows=[]){if(!rows.length)return'<p class="driver-debt-history-empty">No hay pendientes registrados.</p>';return `<div class="admin-debt-existing-list">${rows.map(row=>{const type=debtReasonLabel(row.reason||row.type)||clean(row.reasonLabel||"Pendiente");const driver=clean(row.driverName||row.choferNombre||row.driverUid||"Chofer");const remaining=Math.max(0,Number(row.remainingAmount??row.saldoPendiente??row.totalAmount??row.amount??0));return `<article class="admin-debt-existing-card"><header><strong>${esc(type)} · ${esc(driver)}</strong><span>${esc(debtStatusLabel(row))}</span></header><span>${esc(row.incidentDate||"Sin fecha")} · Saldo ${esc(money(remaining))}</span><button type="button" data-admin-edit-debt="${esc(row.id)}">EDITAR</button></article>`;}).join("")}</div>`;}
function renderAdminDebtList(){const host=$("adminDebtExistingList");if(host)host.innerHTML=debtAdminListMarkup([...state.debts.values()]);}
const clean=value=>String(value??"").trim();
function assignedVehicleIds(profile={}){return[profile.assignedVehicleId,profile.vehicleId,profile.vehiculoId,profile.autoId,profile.vehiculoAsignado,profile.vehiculo].map(clean).filter(Boolean);}
function vehicleLabel(vehicle={}){const plate=clean(vehicle.patente||vehicle.plate||vehicle.dominio).toUpperCase(),label=[vehicle.marca||vehicle.brand,vehicle.modelo||vehicle.model].filter(Boolean).join(" ")||"Vehículo";return{...vehicle,plate,label};}
async function resolveDriverVehicle(profile={}){for(const id of [...new Set(assignedVehicleIds(profile))]){const cached=state.vehicles.get(id);if(cached)return vehicleLabel({id,...cached});const snap=await getDoc(doc(db,"vehiculos",id)).catch(()=>null);if(snap?.exists())return vehicleLabel({id:snap.id,...snap.data()});}const identities=[profile.uid,profile.authUid,profile.firebaseUid,profile.id,profile.usuario,profile.username].map(clean).filter(Boolean);for(const field of ["currentDriverUid","currentDriverDocumentId","choferId","conductorId","driverId","asignadoA","chofer","uidChofer"]){for(const identity of identities){const snap=await getDocs(query(collection(db,"vehiculos"),where(field,"==",identity),limit(1))).catch(()=>null);if(snap&&!snap.empty){const item=snap.docs[0];return vehicleLabel({id:item.id,...item.data()});}}}return null;}
function setSelectedVehicleById(id){const raw=state.vehicles.get(clean(id));state.selectedVehicle=raw?vehicleLabel({id:clean(id),...raw}):null;const box=$("adminDebtVehicle");if(box)box.textContent=state.selectedVehicle?`${state.selectedVehicle.label} · ${state.selectedVehicle.plate||"Sin patente"}`:"Sin vehículo relacionado";updateDebtSummary();}
async function syncSelectedVehicle(){const uid=clean($("adminDebtDriver")?.value),box=$("adminDebtVehicle"),select=$("adminDebtVehicleSelect");state.selectedVehicle=null;if(!uid){if(box)box.textContent="Selecciona un chofer";if(select)select.value="";updateDebtSummary();return;}if(box)box.textContent="Buscando vehículo asignado…";try{state.selectedVehicle=await resolveDriverVehicle(state.drivers.get(uid)||{});if(select)select.value=state.selectedVehicle?.id||"";if(box)box.textContent=state.selectedVehicle?`${state.selectedVehicle.label} · ${state.selectedVehicle.plate||"Sin patente"}`:"Sin vehículo asignado; puedes seleccionar el involucrado";}catch(error){console.error("ADMIN_DEBT_VEHICLE_LOOKUP_FAILED",error);if(box)box.textContent="No se pudo consultar el vehículo";}updateDebtSummary();}
function clearReceipt(){window.ExploraReceiptEngine?.resetUploadState?.("driverDebt");state.receiptFile=null;const input=$("driverDebtReceiptInput");if(input)input.value="";window.ExploraReceiptUI?.clear?.({previewId:"adminDebtReceiptPreview",thumbId:"adminDebtReceiptPreviewThumb",nameId:"adminDebtReceiptPreviewName",metaId:"adminDebtReceiptPreviewMeta"});updateDebtSummary();}
function selectReceipt(file){const message=$("adminDebtMessage");if(!file)return;try{const selected=window.ExploraReceiptEngine?.selectUploadFile?.(file,"driverDebt",{allowPdf:true});state.receiptFile=selected.file;const rendered=window.ExploraReceiptUI?.render?.({previewId:"adminDebtReceiptPreview",thumbId:"adminDebtReceiptPreviewThumb",nameId:"adminDebtReceiptPreviewName",metaId:"adminDebtReceiptPreviewMeta",file,previewUrl:selected.previewUrl});if(!rendered&&String(file.type||"").toLowerCase().includes("pdf")){const preview=$("adminDebtReceiptPreview"),thumb=$("adminDebtReceiptPreviewThumb"),name=$("adminDebtReceiptPreviewName"),meta=$("adminDebtReceiptPreviewMeta");if(preview)preview.hidden=false;if(thumb){thumb.removeAttribute("src");thumb.alt="PDF";thumb.dataset.fileType="pdf";}if(name)name.textContent=file.name||"Archivo PDF";if(meta)meta.textContent=`PDF · ${Math.max(1,Math.round(Number(file.size||0)/1024))} KB`;}if(message&&!state.diagnostic){message.textContent="";message.className="admin-shared-status";}updateDebtSummary();window.scrollToReceiptSubmitButton?.($("adminDebtSubmit"));}catch(error){const runtime=baseRuntime();runtime.stage="FORM_VALIDATION";showDebtFailure(makeDebtError("FORM_VALIDATION","INVALID_RECEIPT_FILE",String(error?.message||"").includes("TOO_LARGE")?"El archivo es demasiado pesado.":"Selecciona una imagen o PDF válido.",error),runtime);}}
function updateDebtSummary({recalculateWeekly=false}={}){const amount=parseAmount($("adminDebtAmount")?.value),count=Math.max(1,Math.min(52,Number($("adminDebtInstallmentCount")?.value||state.installments||1)));state.installments=count;const weeklyInput=$("adminDebtWeeklyAmount");if(recalculateWeekly&&weeklyInput&&amount>0)weeklyInput.value=formatAmount(Math.ceil(amount/count));const weekly=parseAmount(weeklyInput?.value)||Math.ceil(amount/count||1);const box=$("adminDebtSummary"),button=$("adminDebtSubmit");if(box)box.innerHTML=`<div><span>Deuda total</span><strong>${money(amount)}</strong></div><div><span>Cuotas semanales</span><strong>${count}</strong></div><div><span>Cuota semanal</span><strong>${money(weekly)}</strong></div><div><span>Vehículo</span><strong>${esc(state.selectedVehicle?.plate||"—")}</strong></div>`;const editing=state.editingDebtId?state.debts.get(state.editingDebtId)||{}:null,paid=Math.max(0,Number(editing?.paidAmount||0)),paidCount=Math.max(0,Number(editing?.paidInstallments||0)),remaining=Math.max(0,amount-paid),futureCount=Math.max(1,count-paidCount);const validPlan=amount>0&&weekly>0&&(editing?weekly*futureCount>=remaining:weekly*count>=amount);const valid=Boolean(clean($("adminDebtDriver")?.value)&&state.reason&&$("adminDebtDate")?.value&&clean($("adminDebtDescription")?.value)&&validPlan);if(button)button.disabled=state.busy||!valid;}
