async function openDebt(){await ensureDebtFirebase();const screen=$("adminSharedScreen"),content=$("adminSharedContent");if(!screen||!content)return;window.ExploraAdminShared?.close?.();screen.classList.add("is-open");screen.setAttribute("aria-hidden","false");window.lockPageScroll?.("admin-debt");$("adminSharedTitle").textContent="PENDIENTES";$("adminSharedSubtitle").textContent="Crear o editar multas, choques, préstamos y adelantos";$("adminSharedPeriodTabs").hidden=true;$("adminSharedReceiptTabs").hidden=true;$("adminSharedStatus").textContent="Cargando choferes…";const [drivers,vehicles,debts]=await Promise.all([activeDrivers().catch(error=>{console.error("ADMIN_DEBT_DRIVERS_LOAD_FAILED",error);return[];}),activeVehicles().catch(error=>{console.error("ADMIN_DEBT_VEHICLES_LOAD_FAILED",error);return[];}),activeDebts().catch(error=>{console.error("ADMIN_DEBT_LIST_LOAD_FAILED",error);return[];})]);$("adminSharedStatus").textContent=drivers.length?"":"No hay choferes activos.";content.innerHTML=`<form id="adminDebtForm" class="debt-form" novalidate><div class="debt-field"><label for="adminDebtDriver">CHOFER</label><select id="adminDebtDriver"><option value="">Selecciona un chofer</option>${drivers.map(profile=>`<option value="${esc(profile.uid||profile.authUid||profile.id)}">${esc(profile.nombre||profile.nombreCompleto||profile.usuario||profile.id)}</option>`).join("")}</select></div><div class="debt-field"><label for="adminDebtVehicleSelect">VEHÍCULO RELACIONADO</label><select id="adminDebtVehicleSelect"><option value="">Sin vehículo relacionado</option>${vehicles.map(vehicle=>{const v=vehicleLabel(vehicle);return`<option value="${esc(v.id)}">${esc(v.label)} · ${esc(v.plate||"Sin patente")}</option>`;}).join("")}</select><div id="adminDebtVehicle" class="debt-vehicle-readonly">Selecciona un chofer</div></div><div class="debt-field"><label>TIPO</label><div class="debt-reason-grid"><button type="button" class="debt-choice" data-debt-reason="fine">MULTA</button><button type="button" class="debt-choice" data-debt-reason="crash">CHOQUE</button><button type="button" class="debt-choice" data-debt-reason="personal_loan">PRÉSTAMO</button><button type="button" class="debt-choice" data-debt-reason="advance">ADELANTO</button></div></div><div class="debt-field"><label for="adminDebtDate">FECHA</label><input id="adminDebtDate" type="date"></div><div class="debt-field"><label for="adminDebtDescription">MOTIVO O DESCRIPCIÓN</label><textarea id="adminDebtDescription" maxlength="320" placeholder="Detalle breve"></textarea></div><div class="debt-field"><label for="adminDebtAmount">IMPORTE TOTAL</label><input id="adminDebtAmount" inputmode="numeric" autocomplete="off" placeholder="$ 0"></div><div class="debt-field"><label for="adminDebtInstallmentCount">CANTIDAD DE CUOTAS SEMANALES</label><input id="adminDebtInstallmentCount" type="number" min="1" max="52" step="1" value="1"></div><div class="debt-field"><label for="adminDebtWeeklyAmount">IMPORTE DE CUOTA SEMANAL</label><input id="adminDebtWeeklyAmount" inputmode="numeric" autocomplete="off" placeholder="$ 0"></div><div class="debt-field"><label>ARCHIVO ADJUNTO <span class="debt-attachment-optional">OPCIONAL · IMAGEN O PDF</span></label>${window.ExploraReceiptUI.markup({triggerId:"adminDebtReceiptBtn",previewId:"adminDebtReceiptPreview",thumbId:"adminDebtReceiptPreviewThumb",nameId:"adminDebtReceiptPreviewName",metaId:"adminDebtReceiptPreviewMeta",removeId:"adminDebtReceiptPreviewRemove",heading:"Archivo adjunto"})}</div><div class="debt-field"><label for="adminDebtNotes">OBSERVACIONES DEL ADMINISTRADOR</label><textarea id="adminDebtNotes" maxlength="320" placeholder="Observaciones opcionales"></textarea></div><div id="adminDebtEditBanner" class="admin-debt-edit-banner" hidden><span>Editando pendiente existente</span><button id="adminDebtCancelEdit" type="button">Cancelar edición</button></div><div id="adminDebtSummary" class="debt-summary"></div><div id="adminDebtMessage" class="admin-shared-status" role="status"></div>${diagnosticMarkup()}<button id="adminDebtSubmit" class="admin-primary-btn admin-debt-submit" type="submit" disabled>REGISTRAR PENDIENTE</button></form><section class="admin-debt-existing"><div class="admin-debt-existing-head"><h3>REGISTROS EXISTENTES</h3><span>${debts.length}</span></div><div id="adminDebtExistingList">${debtAdminListMarkup(debts)}</div></section>`;state.reason="";state.installments=1;state.selectedVehicle=null;state.editingDebtId="";state.opened=true;state.diagnostic=null;clearReceipt();const today=new Intl.DateTimeFormat("en-CA",{timeZone:"America/Argentina/Cordoba",year:"numeric",month:"2-digit",day:"2-digit"}).format(window.ExploraOperationalClock?.getNow?.()||new Date());if($("adminDebtDate"))$("adminDebtDate").value=today;updateDebtSummary({recalculateWeekly:true});}

function setDebtReason(reason){state.reason=DEBT_REASON_OPTIONS.includes(clean(reason))?clean(reason):"";document.querySelectorAll("[data-debt-reason]").forEach(button=>button.classList.toggle("is-selected",button.dataset.debtReason===state.reason));}
function beginDebtEdit(debtId){const row=state.debts.get(clean(debtId));if(!row)return;state.editingDebtId=row.id;clearReceipt();const driverUid=clean(row.driverUid||row.choferUid||row.driverId||row.uid),driverSelect=$("adminDebtDriver"),vehicleSelect=$("adminDebtVehicleSelect");if(driverSelect){if(driverUid&&![...driverSelect.options].some(option=>option.value===driverUid)){const option=document.createElement("option");option.value=driverUid;option.textContent=clean(row.driverName||row.choferNombre||driverUid||"Chofer");driverSelect.appendChild(option);}driverSelect.value=driverUid;driverSelect.disabled=true;}const vehicleId=clean(row.vehicleId||row.originalVehicleId||row.vehiculoId);if(vehicleSelect){vehicleSelect.value=vehicleId;vehicleSelect.disabled=true;}setSelectedVehicleById(vehicleId);setDebtReason(DEBT_REASON_OPTIONS.includes(clean(row.reason||row.type))?clean(row.reason||row.type):(clean(row.reasonLabel).toLowerCase().includes("choque")?"crash":clean(row.reasonLabel).toLowerCase().includes("préstamo")||clean(row.reasonLabel).toLowerCase().includes("prestamo")?"personal_loan":clean(row.reasonLabel).toLowerCase().includes("adelanto")?"advance":"fine"));if($("adminDebtDate"))$("adminDebtDate").value=clean(row.incidentDate).slice(0,10);if($("adminDebtDescription"))$("adminDebtDescription").value=clean(row.description||row.notes);if($("adminDebtAmount"))$("adminDebtAmount").value=formatAmount(String(Math.max(0,Number(row.totalAmount||row.amount||0))));if($("adminDebtInstallmentCount"))$("adminDebtInstallmentCount").value=Math.max(1,Number(row.installmentCount||row.installments||1));if($("adminDebtWeeklyAmount"))$("adminDebtWeeklyAmount").value=formatAmount(String(Math.max(0,Number(row.weeklyInstallmentAmount||row.installmentAmount||0))));if($("adminDebtNotes"))$("adminDebtNotes").value=clean(row.adminNotes||row.notes);const banner=$("adminDebtEditBanner");if(banner)banner.hidden=false;const button=$("adminDebtSubmit");if(button)button.textContent="GUARDAR CAMBIOS";const message=$("adminDebtMessage");if(message){message.textContent="Puedes editar datos administrativos. Los pagos ya aplicados no se modifican.";message.className="admin-shared-status";}updateDebtSummary();$("adminDebtForm")?.scrollIntoView?.({behavior:"smooth",block:"start"});}
