document.addEventListener("click",event=>{if(!state.opened)return;if(event.target.closest?.("#adminDebtDiagnosticClose")){closeDebtDiagnostic();return;}if(event.target.closest?.("#adminDebtDiagnosticCopy")){copyDebtDiagnostic();return;}const edit=event.target.closest?.("[data-admin-edit-debt]");if(edit){beginDebtEdit(edit.dataset.adminEditDebt);return;}if(event.target.closest?.("#adminDebtCancelEdit")){cancelDebtEdit();return;}const reason=event.target.closest?.("[data-debt-reason]");if(reason){setDebtReason(reason.dataset.debtReason);updateDebtSummary();return;}if(event.target.closest?.("#adminDebtReceiptBtn")){$("driverDebtReceiptInput")?.click();return;}if(event.target.closest?.("#adminDebtReceiptPreviewRemove")){clearReceipt();return;}});
document.addEventListener("input",event=>{if(!state.opened)return;if(event.target?.id==="adminDebtAmount"){event.target.value=formatAmount(event.target.value);updateDebtSummary({recalculateWeekly:true});}else if(event.target?.id==="adminDebtWeeklyAmount"){event.target.value=formatAmount(event.target.value);updateDebtSummary();}else if(["adminDebtInstallmentCount","adminDebtDate","adminDebtDescription","adminDebtNotes"].includes(event.target?.id))updateDebtSummary({recalculateWeekly:event.target.id==="adminDebtInstallmentCount"});});
document.addEventListener("change",event=>{if(!state.opened)return;if(event.target?.id==="adminDebtDriver")syncSelectedVehicle();if(event.target?.id==="adminDebtVehicleSelect")setSelectedVehicleById(event.target.value);if(event.target?.id==="driverDebtReceiptInput")selectReceipt(event.target.files?.[0]);});
